}
int main() {
  *h = 10;
j:
  a = 3;
  for (; a; a--) {
    f = 0;
    for (; f <= 3; f++)
      if (e[1]) {
        b = 3;
        for (; b; b--) {
          int *k = &c;
          if (d) {
            i(e);
